//! Parity gate for `decode_step_batch` (the continuous-batch decode kernel).
//!
//! A batched K-sequence decode step must produce, per sequence, the SAME
//! next-token prediction as K independent single-sequence `forward_one` decode
//! runs of the same prompt. The batched path shares each layer's weight read
//! across the wave (the amortization) but the attention is per-sequence, so the
//! result must be identical — only throughput changes, not the tokens. Tiny
//! synthetic llama (qwen2 arch, no bias/qk-norm) so it runs in-process, no I/O.

use distributed_inference::kv_cache::KVCache;
use distributed_inference::loader::{KnotConfig, OwnedBytes, TensorInfo, WeightBackend};
use distributed_inference::model::NativeLlamaPipeline;
use std::any::Any;
use std::collections::HashMap;
use std::sync::Arc;

const D: usize = 32; // hidden_dim
const LAYERS: usize = 2;
const HEADS: usize = 4;
const KV_HEADS: usize = 4;
const HEAD_DIM: usize = 8; // D / HEADS
const INTER: usize = 64; // intermediate_size
const VOCAB: usize = 48;

// ── Mock weight backend (mirrors rwkv7_integration_test) ─────────────────────
struct MockBackend {
    store: HashMap<String, Vec<u8>>,
}
impl MockBackend {
    fn new() -> Self {
        Self { store: HashMap::new() }
    }
    fn put(&mut self, name: &str, v: Vec<f32>) {
        let bytes: Vec<u8> = v.iter().flat_map(|f| f.to_le_bytes()).collect();
        self.store.insert(name.to_string(), bytes);
    }
    fn fill(&mut self, name: &str, n: usize, seed: f32) {
        self.put(name, (0..n).map(|i| (i as f32 * seed).sin() * 0.05).collect());
    }
    fn ones(&mut self, name: &str, n: usize) {
        self.put(name, vec![1.0f32; n]);
    }
}
unsafe impl Send for MockBackend {}
unsafe impl Sync for MockBackend {}
impl WeightBackend for MockBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        self.store
            .get(name)
            .or_else(|| self.store.get(bare))
            .map(|b| OwnedBytes::Owned(Arc::new(b.clone())))
            .ok_or_else(|| format!("MockBackend: missing {name:?}"))
    }
    fn has_tensor(&self, name: &str) -> bool {
        let bare = name.strip_suffix(".bin").unwrap_or(name);
        self.store.contains_key(name) || self.store.contains_key(bare)
    }
    fn as_any(&self) -> &dyn Any {
        self
    }
}

fn make_pipeline() -> NativeLlamaPipeline {
    let qkv = HEADS * HEAD_DIM;
    let kv = KV_HEADS * HEAD_DIM;
    let mut b = MockBackend::new();
    b.fill("token_embd_weight", VOCAB * D, 0.01);
    b.ones("output_norm_weight", D);
    b.fill("output_weight", VOCAB * D, 0.02);
    for i in 0..LAYERS {
        b.ones(&format!("blk_{}_attn_norm_weight", i), D);
        b.fill(&format!("blk_{}_attn_q_weight", i), qkv * D, 0.03);
        b.fill(&format!("blk_{}_attn_k_weight", i), kv * D, 0.031);
        b.fill(&format!("blk_{}_attn_v_weight", i), kv * D, 0.029);
        b.fill(&format!("blk_{}_attn_output_weight", i), D * qkv, 0.027);
        b.ones(&format!("blk_{}_ffn_norm_weight", i), D);
        b.fill(&format!("blk_{}_ffn_gate_weight", i), INTER * D, 0.02);
        b.fill(&format!("blk_{}_ffn_up_weight", i), INTER * D, 0.018);
        b.fill(&format!("blk_{}_ffn_down_weight", i), D * INTER, 0.022);
    }
    let mut meta: HashMap<String, TensorInfo> = HashMap::new();
    for (name, bytes) in b.store.iter() {
        meta.insert(
            name.clone(),
            TensorInfo {
                offset: 0,
                length: bytes.len() as u64,
                tensor_type: "F32".to_string(),
                shape: None,
            },
        );
    }
    let cfg: KnotConfig = serde_json::from_str(&format!(
        r#"{{"hidden_dim":{},"num_layers":{},"num_heads":{},"num_kv_heads":{},"head_dim":{},"intermediate_size":{},"vocab_size":{},"arch":"qwen2"}}"#,
        D, LAYERS, HEADS, KV_HEADS, HEAD_DIM, INTER, VOCAB
    ))
    .expect("KnotConfig parse");
    NativeLlamaPipeline::from_parts(Arc::new(b), meta, Some(cfg), 0, false, 0.0, None, None)
}

fn argmax(v: &[f32]) -> usize {
    v.iter()
        .enumerate()
        .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
        .unwrap()
        .0
}

#[test]
fn decode_step_batch_parity() {
    // K sequences, each its own prompt (divergent ⇒ exercises batch isolation).
    let seqs: [&[usize]; 3] = [&[1, 5, 2, 9], &[7, 1, 3, 4], &[2, 2, 8, 0]];
    let k = seqs.len();
    let t_len = seqs[0].len();

    // Solo reference: one fresh pipeline per sequence, autoregressive forward_one.
    let mut solo: Vec<Vec<f32>> = Vec::new();
    for s in 0..k {
        let mut p = make_pipeline();
        for (t, &tok) in seqs[s].iter().enumerate() {
            p.forward_one(tok, t, false).expect("forward_one");
        }
        solo.push(p.get_logits().to_vec());
    }

    // Batched: one pipeline, K per-sequence KVCache slabs + positions.
    let mut p = make_pipeline();
    let mut seq_kv: Vec<KVCache> = (0..k).map(|_| KVCache::new(LAYERS, KV_HEADS, HEAD_DIM, 16)).collect();
    let mut positions = vec![0usize; k];
    let mut last = vec![0f32; k * VOCAB];
    for t in 0..t_len {
        let toks: Vec<u32> = (0..k).map(|s| seqs[s][t] as u32).collect();
        last = p.decode_step_batch(&mut seq_kv, &mut positions, &toks).expect("decode_step_batch");
    }

    for s in 0..k {
        let batched = &last[s * VOCAB..(s + 1) * VOCAB];
        let solo_s = &solo[s];
        assert!(batched.iter().all(|v| v.is_finite()), "lane {s} non-finite logits");
        // The prediction (argmax) MUST match — same next token, exactly.
        assert_eq!(argmax(batched), argmax(solo_s), "lane {s}: batched argmax != solo");
        // And the full logit vector close (same arithmetic up to batched-GEMM assoc).
        let maxdiff = batched.iter().zip(solo_s).map(|(a, b)| (a - b).abs()).fold(0.0f32, f32::max);
        assert!(maxdiff < 1e-2, "lane {s}: logits diverge, maxdiff {maxdiff}");
    }
}

/// M3 ragged-lane parity — lanes at DIVERGENT positions must not cross-leak.
///
/// Continuous batching (M5) admits a new request into a freed lane mid-wave: it
/// starts at position 0 while its siblings are at position N. This certifies
/// `decode_step_batch` attends each lane over ONLY its own `0..=positions[i]`
/// slab with no cross-lane contamination at ragged positions — the operational
/// form of `VGpuWarp.lean :step_no_crosstalk` / `:batch_isolation`.
#[test]
fn decode_step_batch_ragged_admission_parity() {
    // Two "resident" lanes prefilled to position N, then a third admitted fresh
    // at position 0 — the batch runs at positions [N, N, 0].
    let resident: [&[usize]; 2] = [&[1, 5, 2, 9, 3], &[7, 1, 3, 4, 6]]; // len 5
    let newcomer: &[usize] = &[2, 8]; // admitted lane, len 2

    // Solo references (independent autoregressive forward_one per sequence).
    let solo_logits = |seq: &[usize]| -> Vec<f32> {
        let mut p = make_pipeline();
        for (t, &tok) in seq.iter().enumerate() {
            p.forward_one(tok, t, false).expect("forward_one");
        }
        p.get_logits().to_vec()
    };
    let solo_r0 = solo_logits(resident[0]);
    let solo_r1 = solo_logits(resident[1]);
    let solo_new = solo_logits(newcomer);

    let mut p = make_pipeline();
    let mut kv: Vec<KVCache> = (0..3).map(|_| KVCache::new(LAYERS, KV_HEADS, HEAD_DIM, 16)).collect();
    let mut pos = vec![0usize; 3];

    // Prefill lanes 0,1 to position N (5 tokens) — lane 2 idle (fed a filler it
    // will be RESET before admission, so its stale KV must not affect anyone).
    let n = resident[0].len();
    for t in 0..n {
        let toks: Vec<u32> = vec![resident[0][t] as u32, resident[1][t] as u32, 0u32];
        p.decode_step_batch(&mut kv, &mut pos, &toks).expect("prefill step");
    }

    // Admit lane 2: fresh slab + position 0 (the continuous-batch reset), then
    // decode its first token in the SAME wave as the two position-N residents.
    kv[2] = KVCache::new(LAYERS, KV_HEADS, HEAD_DIM, 16);
    pos[2] = 0;
    // Residents continue with their next real token; newcomer starts token 0.
    // positions is now [5, 5, 0] — the ragged wave.
    let toks: Vec<u32> = vec![resident[0][0] as u32, resident[1][0] as u32, newcomer[0] as u32];
    let _ = p.decode_step_batch(&mut kv, &mut pos, &toks).expect("ragged step");
    // Advance the newcomer one more token so its position (1) diverges further
    // from the residents (6) — a second ragged step.
    let toks2: Vec<u32> = vec![resident[0][1] as u32, resident[1][1] as u32, newcomer[1] as u32];
    let last = p.decode_step_batch(&mut kv, &mut pos, &toks2).expect("ragged step 2");

    // The newcomer lane, at its own low position, must predict as if run solo —
    // i.e. its two-token history alone, uncontaminated by the position-6 residents.
    let new_lane = &last[2 * VOCAB..3 * VOCAB];
    assert!(new_lane.iter().all(|v| v.is_finite()), "ragged newcomer non-finite");
    assert_eq!(
        argmax(new_lane),
        argmax(&solo_new),
        "ragged admission: newcomer argmax leaked from position-N residents"
    );
    let maxdiff = new_lane.iter().zip(&solo_new).map(|(a, b)| (a - b).abs()).fold(0.0f32, f32::max);
    assert!(maxdiff < 1e-2, "ragged newcomer logits diverge, maxdiff {maxdiff}");

    // And the residents are unaffected by a lane joining/leaving at a low position.
    let r0 = &last[0..VOCAB];
    let r1 = &last[VOCAB..2 * VOCAB];
    assert!(r0.iter().all(|v| v.is_finite()) && r1.iter().all(|v| v.is_finite()));
    let _ = (&solo_r0, &solo_r1); // residents advanced past their prompts; finiteness is the guard here
}

/// M4+M5 — the continuous-batch DRIVER certified end-to-end (reference impl).
///
/// This is the algebra the fat-station `/generate-batch` endpoint + BatchScheduler
/// wrap: a bounded set of lane slots, each a (KVCache, position, remaining) job;
/// every step gathers one token per LIVE lane, runs `decode_step_batch` (the
/// amortized shared read), samples per lane (greedy), retires lanes that hit
/// their token budget, and REFILLS a freed slot from the pending queue with a
/// fresh KV at position 0 (continuous-batch admission). Certifies each job's
/// emitted tokens equal a solo autoregressive `forward_one` run — proving the
/// fill/retire/refill loop preserves per-request identity.
///
/// Grounds: `VGpuWarp.lean` :retire_independent_of_mask (one decode, N lanes),
/// :safe_reconverge (a retired lane doesn't resurrect / corrupt siblings),
/// :batch_isolation (per-lane result == solo). This is the layer the vGPU report
/// flagged unbuilt; here it is proven on the real kernel.
#[test]
fn continuous_batch_driver_parity() {
    // Jobs of DIVERGENT lengths so lanes retire + refill at different steps.
    let jobs: Vec<Vec<usize>> = vec![
        vec![1, 5, 2, 9, 3, 7],
        vec![7, 1, 3],
        vec![2, 8, 0, 4],
        vec![9, 9, 1, 2, 5],
        vec![4, 0, 6],
    ];
    let gen_tokens = 3; // tokens to emit per job past its prompt

    // ── Solo reference: greedy autoregression per job (prompt then gen_tokens). ──
    let solo_run = |prompt: &[usize]| -> Vec<usize> {
        let mut p = make_pipeline();
        let mut pos = 0usize;
        for &tok in prompt {
            p.forward_one(tok, pos, false).expect("solo prompt");
            pos += 1;
        }
        let mut out = Vec::new();
        let mut tok = argmax(p.get_logits());
        for _ in 0..gen_tokens {
            out.push(tok);
            p.forward_one(tok, pos, false).expect("solo gen");
            pos += 1;
            tok = argmax(p.get_logits());
        }
        out
    };
    let expected: Vec<Vec<usize>> = jobs.iter().map(|j| solo_run(j)).collect();

    // ── The scheduler: LANES slots, a pending queue, fill/step/retire/refill. ──
    const LANES_N: usize = 3; // fewer slots than jobs ⇒ forces refill/admission
    struct Lane {
        job: usize,
        kv: KVCache,
        pos: usize,
        // Remaining prompt tokens to feed, then the gen phase.
        prompt: std::collections::VecDeque<usize>,
        emitted: Vec<usize>,
        next_tok: usize,   // token to feed this step
        in_gen: bool,
    }
    let mut pending: std::collections::VecDeque<usize> = (0..jobs.len()).collect();
    let mut got: Vec<Vec<usize>> = vec![Vec::new(); jobs.len()];

    let mut p = make_pipeline();
    let mk_lane = |job: usize| -> Lane {
        let mut prompt: std::collections::VecDeque<usize> = jobs[job].iter().copied().collect();
        let first = prompt.pop_front().expect("nonempty prompt");
        Lane {
            job,
            kv: KVCache::new(LAYERS, KV_HEADS, HEAD_DIM, 32),
            pos: 0,
            prompt,
            emitted: Vec::new(),
            next_tok: first,
            in_gen: false,
        }
    };

    let mut lanes: Vec<Option<Lane>> = (0..LANES_N).map(|_| pending.pop_front().map(mk_lane)).collect();

    // Run until all jobs done.
    let mut guard = 0;
    loop {
        guard += 1;
        assert!(guard < 10_000, "scheduler did not converge");
        // Live lanes this step.
        let live: Vec<usize> = (0..LANES_N).filter(|&i| lanes[i].is_some()).collect();
        if live.is_empty() {
            break;
        }
        // Gather one token + position per live lane (batch order = live order).
        let toks: Vec<u32> = live.iter().map(|&i| lanes[i].as_ref().unwrap().next_tok as u32).collect();
        let mut kvs: Vec<KVCache> = Vec::with_capacity(live.len());
        let mut poss: Vec<usize> = Vec::with_capacity(live.len());
        for &i in &live {
            let l = lanes[i].as_mut().unwrap();
            // move the KV out for the batched call, swap a placeholder back after.
            kvs.push(std::mem::replace(&mut l.kv, KVCache::new(1, 1, 1, 1)));
            poss.push(l.pos);
        }
        let logits = p.decode_step_batch(&mut kvs, &mut poss, &toks).expect("driver step");
        // Return KVs + advanced positions to their lanes.
        for (bi, &i) in live.iter().enumerate() {
            let l = lanes[i].as_mut().unwrap();
            l.kv = std::mem::replace(&mut kvs[bi], KVCache::new(1, 1, 1, 1));
            l.pos = poss[bi];
        }
        // Per-lane: pick next token / advance prompt / retire.
        for (bi, &i) in live.iter().enumerate() {
            let done = {
                let l = lanes[i].as_mut().unwrap();
                if let Some(next_prompt) = l.prompt.pop_front() {
                    // Still feeding prompt: ignore logits, feed next prompt token.
                    l.next_tok = next_prompt;
                    false
                } else {
                    // Gen phase: the just-produced logits ARE this lane's next token.
                    let lane_logits = &logits[bi * VOCAB..(bi + 1) * VOCAB];
                    let tok = argmax(lane_logits);
                    if !l.in_gen {
                        l.in_gen = true;
                    }
                    l.emitted.push(tok);
                    l.next_tok = tok;
                    l.emitted.len() >= gen_tokens
                }
            };
            if done {
                let l = lanes[i].take().unwrap();
                got[l.job] = l.emitted;
                // Refill this freed slot from the queue (continuous admission).
                lanes[i] = pending.pop_front().map(&mk_lane);
            }
        }
    }

    for j in 0..jobs.len() {
        assert_eq!(
            got[j], expected[j],
            "continuous-batch job {j}: scheduled tokens != solo autoregressive"
        );
    }
}
